func loadManifest(path string) (*DependencyManifest, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, err
	}

	var manifest DependencyManifest
	if err := json.Unmarshal(data, &manifest); err != nil {
		return nil, err
	}

	return &manifest, nil
}

func getCacheDir() (string, error) {
	home, err := os.UserHomeDir()
	if err != nil {
		return "", err
	}
	return filepath.Join(home, ".go-secure-cache"), nil
}

func loadTrustedCertificates() []string {
	certPath := os.Getenv("TRUSTED_CERTS_PATH")
	if certPath == "" {
		return nil
	}

	data, err := os.ReadFile(certPath)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Warning: could not load trusted certificates: %v\n", err)
		return nil
	}

	return strings.Split(string(data), "\n")
}

func createSecureHTTPClient(trustedCerts []string) *http.Client {
	tlsConfig := &tls.Config{
		MinVersion: tls.VersionTLS12,
		CipherSuites: []uint16{
			tls.TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384,
			tls.TLS_ECDHE_RSA_WITH_AES_128_GCM_SHA256,
			tls.TLS_ECDHE_ECDSA_WITH_AES_256_GCM_SHA384,
			tls.TLS_ECDHE_ECDSA_WITH_AES_128_GCM_SHA256,
		},
	}

	return &http.Client{
		Timeout: 5 * time.Minute,
		Transport: &http.Transport{
			TLSClientConfig: tlsConfig,
		},
	}
}

func verifyAndInstallDependency(dep Dependency, cacheDir string, client *http.Client) error {
	packagePath := strings.ReplaceAll(dep.Package, "/", "_")
	versionedPath := fmt.Sprintf("%s@%s", packagePath, dep.Version)
	cachedPath := filepath.Join(cacheDir, versionedPath)

	if _, err := os.Stat(cachedPath); err == nil {
		fmt.Printf("  Using cached version\n")
		return installFromCache(cachedPath, dep)
	}

	tempDir, err := os.MkdirTemp("", "go-install-*")
	if err != nil {
		return err
	}
	defer os.RemoveAll(tempDir)

	if err := downloadAndVerify(dep, tempDir, client); err != nil {
		return err
	}

	if err := os.MkdirAll(filepath.Dir(cachedPath), 0700); err != nil {
		return err
	}

	if err := os.Rename(tempDir, cachedPath); err != nil {
		return err
	}

	return installFromCache(cachedPath, dep)
}

func downloadAndVerify(dep Dependency, destDir string, client *http.Client) error {
	env := os.Environ()
	env = append(env, "GO111MODULE=on")
	env = append(env, fmt.Sprintf("GOPATH=%s", destDir))

	packageWithVersion := fmt.Sprintf("%s@%s", dep.Package, dep.Version)
	
	cmd := exec.Command("go", "get", "-d", packageWithVersion)
	cmd.Env = env
	cmd.Stdout = os.Stdout
	cmd.Stderr = os.Stderr

	if err := cmd.Run(); err != nil {
		return fmt.Errorf("go get failed: %w", err)
	}

	if dep.Checksum != "" {
		if err := verifyChecksum(destDir, dep.Checksum); err != nil {
			return fmt.Errorf("checksum verification failed: %w", err)
		}
		fmt.Printf("  Checksum verified\n")
	}

	if dep.Source != "" {
		if err := verifySource(dep, client); err != nil {
			return fmt.Errorf("source verification failed: %w", err)
		}
		fmt.Printf("  Source verified\n")
	}

	return nil
}

func verifyChecksum(dir string, expectedChecksum string) error {
	hash := sha256.New()

	err := filepath.Walk(dir, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}
		if info.IsDir() {
			return nil
		}

		file, err := os.Open(path)
		if err != nil {
			return err
		}
		defer file.Close()

		if _, err := io.Copy(hash, file); err != nil {
			return err
		}

		return nil
	})

	if err != nil {
		return err
	}

	actualChecksum := hex.EncodeToString(hash.Sum(nil))
	if actualChecksum != expectedChecksum {
		return fmt.Errorf("checksum mismatch: expected %s, got %s", expectedChecksum, actualChecksum)
	}

	return nil
}

func verifySource(dep Dependency, client *http.Client) error {
	resp, err := client.Get(dep.Source)
	if err != nil {
		return err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return fmt.Errorf("source verification returned status %d", resp.StatusCode)
	}

	return nil
}

func installFromCache(cachedPath string, dep Dependency) error {
	gopath := os.Getenv("GOPATH")
	if gopath == "" {
		home, err := os.UserHomeDir()
		if err != nil {
			return err
		}
		gopath = filepath.Join(home, "go")
	}

	srcDir := filepath.Join(gopath, "src")
	if err := os.MkdirAll(srcDir, 0755); err != nil {
		return err
	}

	destPath := filepath.Join(srcDir, dep.Package)
	if err := os.MkdirAll(filepath.Dir(destPath), 0755); err != nil {
		return err
	}

	if err := copyDir(cachedPath, destPath); err != nil {
		return err
	}

	fmt.Printf("  Installed to %s\n", destPath)
	return nil
}

func copyDir(src, dst string) error {
	return filepath.Walk(src, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}

		relPath, err := filepath.Rel(src, path)
		if err != nil {
			return err
		}

		dstPath := filepath.Join(dst, relPath)

		if info.IsDir() {
			return os.MkdirAll(dstPath, info.Mode())
		}

		return copyFile(path, dstPath, info.Mode())
	})
}

func copyFile(src, dst string, mode os.FileMode) error {
	srcFile, err := os.Open(src)
	if err != nil {
		return err
	}
	defer srcFile.Close()

	dstFile, err := os.OpenFile(dst, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, mode)
	if err != nil {
		return err
	}
	defer dstFile.Close()

	_, err = io.Copy(dstFile, srcFile)
	return err
}